import{_ as e,o as s,c as i,ae as t}from"./chunks/framework.D7zHIyZF.js";const u=JSON.parse('{"title":"Recipes","description":"","frontmatter":{"title":"Recipes"},"headers":[],"relativePath":"recipes.md","filePath":"recipes.md"}'),n={name:"recipes.md"};function l(o,a,d,h,c,p){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="recipes" tabindex="-1">Recipes <a class="header-anchor" href="#recipes" aria-label="Permalink to &quot;Recipes&quot;">​</a></h1><p>Practical examples for common jai setups.</p><h2 id="claude-code" tabindex="-1">Claude Code <a class="header-anchor" href="#claude-code" aria-label="Permalink to &quot;Claude Code&quot;">​</a></h2><h3 id="install-claude-code-in-its-own-jail" tabindex="-1">Install Claude Code in its own jail <a class="header-anchor" href="#install-claude-code-in-its-own-jail" aria-label="Permalink to &quot;Install Claude Code in its own jail&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://claude.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -D</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -mstrict</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span></code></pre></div><ul><li><code>-D</code> suppresses granting the current directory (you&#39;re installing, not coding)</li><li><code>-mstrict</code> uses strict mode with a separate user ID</li><li><code>-j claude</code> creates a named jail called <code>claude</code></li><li>The installer runs inside the jail and writes to <code>$HOME/.jai/claude.home</code></li></ul><h3 id="run-claude-code-from-that-jail" tabindex="-1">Run Claude Code from that jail <a class="header-anchor" href="#run-claude-code-from-that-jail" aria-label="Permalink to &quot;Run Claude Code from that jail&quot;">​</a></h3><p>If <code>$HOME/.local/bin</code> is already on your <code>PATH</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span></span></code></pre></div><p>Otherwise:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.local/bin:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PATH </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span></span></code></pre></div><h3 id="make-jai-claude-use-the-claude-jail-by-default" tabindex="-1">Make <code>jai claude</code> use the claude jail by default <a class="header-anchor" href="#make-jai-claude-use-the-claude-jail-by-default" aria-label="Permalink to &quot;Make \`jai claude\` use the claude jail by default&quot;">​</a></h3><p>Create <code>$HOME/.jai/claude.conf</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>conf .defaults</span></span>
<span class="line"><span>jail claude</span></span>
<span class="line"><span>setenv PATH=\${HOME}/.local/bin:\${PATH}</span></span></code></pre></div><p>(Note the braces are required around environment variables: <code>\${HOME}</code> expands to your home directory while <code>$HOME</code> does not expand.) Now you can simply run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span></span></code></pre></div><p>jai will find <code>claude.conf</code>, use the <code>claude</code> jail in strict mode, and prepend the executable directory to <code>PATH</code>.</p><h2 id="codex" tabindex="-1">Codex <a class="header-anchor" href="#codex" aria-label="Permalink to &quot;Codex&quot;">​</a></h2><h3 id="run-codex-in-casual-mode" tabindex="-1">Run Codex in casual mode <a class="header-anchor" href="#run-codex-in-casual-mode" aria-label="Permalink to &quot;Run Codex in casual mode&quot;">​</a></h3><p>If Codex stores configuration in <code>~/.codex</code>, expose that directory so you can delete your jail state without losing your codex configuration:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span></span></code></pre></div><h3 id="make-jai-codex-do-this-by-default" tabindex="-1">Make <code>jai codex</code> do this by default <a class="header-anchor" href="#make-jai-codex-do-this-by-default" aria-label="Permalink to &quot;Make \`jai codex\` do this by default&quot;">​</a></h3><p>Create <code>$HOME/.jai/codex.conf</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Read the configuration for the default sandbox</span></span>
<span class="line"><span>conf default</span></span>
<span class="line"><span></span></span>
<span class="line"><span># But also expose $HOME/.codex</span></span>
<span class="line"><span>dir .codex</span></span></code></pre></div><p>Now <code>jai codex</code> automatically exposes <code>~/.codex</code>. If you want to run a shell and see what codex&#39;s sandbox looks like, just specify the configuration explicitly as in <code>jai -C codex</code>.</p><h2 id="opencode" tabindex="-1">OpenCode <a class="header-anchor" href="#opencode" aria-label="Permalink to &quot;OpenCode&quot;">​</a></h2><h3 id="run-opencode-in-casual-mode" tabindex="-1">Run OpenCode in casual mode <a class="header-anchor" href="#run-opencode-in-casual-mode" aria-label="Permalink to &quot;Run OpenCode in casual mode&quot;">​</a></h3><p>OpenCode uses two directories for state:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.local/share/opencode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opencode</span></span></code></pre></div><h3 id="make-jai-opencode-do-this-by-default" tabindex="-1">Make <code>jai opencode</code> do this by default <a class="header-anchor" href="#make-jai-opencode-do-this-by-default" aria-label="Permalink to &quot;Make \`jai opencode\` do this by default&quot;">​</a></h3><p>Create <code>$HOME/.jai/opencode.conf</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>conf default.conf</span></span>
<span class="line"><span>dir .config/opencode</span></span>
<span class="line"><span>dir .local/share/opencode</span></span></code></pre></div><h2 id="python-virtualenv" tabindex="-1">Python virtualenv <a class="header-anchor" href="#python-virtualenv" aria-label="Permalink to &quot;Python virtualenv&quot;">​</a></h2><h3 id="run-python-with-a-jailed-virtualenv" tabindex="-1">Run Python with a jailed virtualenv <a class="header-anchor" href="#run-python-with-a-jailed-virtualenv" aria-label="Permalink to &quot;Run Python with a jailed virtualenv&quot;">​</a></h3><p>Create <code>$HOME/.jai/python.conf</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>conf default.conf</span></span>
<span class="line"><span>mode strict</span></span>
<span class="line"><span>dir venv</span></span>
<span class="line"><span>jail python</span></span>
<span class="line"><span>command source $HOME/venv/bin/activate; &quot;$0&quot; &quot;$@&quot;</span></span></code></pre></div><p>Now <code>jai python</code> enters strict mode, exposes the <code>venv</code> directory, activates the virtualenv, and runs whatever Python command you provide.</p><h2 id="multiple-named-jails" tabindex="-1">Multiple named jails <a class="header-anchor" href="#multiple-named-jails" aria-label="Permalink to &quot;Multiple named jails&quot;">​</a></h2><p>Named jails let you isolate tools from each other. Each gets its own home directory:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # strict jail named &quot;claude&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # strict jail named &quot;codex&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scratch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # strict jail named &quot;scratch&quot; (bash is optional)</span></span></code></pre></div><p>Each jail has independent state:</p><ul><li>Strict/bare home: <code>$HOME/.jai/&lt;name&gt;.home</code></li><li>Casual overlay changes: <code>$HOME/.jai/&lt;name&gt;.changes</code></li><li>Private tmp: <code>/run/jai/$USER/tmp/&lt;name&gt;</code></li></ul><h2 id="cleanup-and-reset" tabindex="-1">Cleanup and reset <a class="header-anchor" href="#cleanup-and-reset" aria-label="Permalink to &quot;Cleanup and reset&quot;">​</a></h2><h3 id="tear-down-all-jails" tabindex="-1">Tear down all jails <a class="header-anchor" href="#tear-down-all-jails" aria-label="Permalink to &quot;Tear down all jails&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span></span></code></pre></div><p>This unmounts all overlay directories from <code>/run/jai</code>, cleans up <code>.work</code> directories, and destroys private <code>/tmp</code> and <code>/var/tmp</code> contents. Run this when:</p><ul><li>You want to start from scratch</li><li>You changed <code>--mask</code> options in a config file (masks are only applied when the overlay is first created)</li><li>You need to edit files in <code>$HOME/.jai/*.changes</code> directly</li><li>Overlay mounts are behaving strangely</li></ul><h3 id="recover-changes-from-casual-mode" tabindex="-1">Recover changes from casual mode <a class="header-anchor" href="#recover-changes-from-casual-mode" aria-label="Permalink to &quot;Recover changes from casual mode&quot;">​</a></h3><p>If jailed software modified config files in your home directory, you&#39;ll find those changes in:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$HOME/.jai/default.changes/</span></span></code></pre></div><p>(Or <code>$HOME/.jai/&lt;name&gt;.changes/</code> for named jails.)</p><p>To move these changes into your real home:</p><ol><li>Run <code>jai -u</code> to unmount the overlay</li><li>Copy the changed files from the <code>.changes</code> directory to your home</li><li>Re-run <code>jai</code> — optionally adding <code>-d</code> flags for directories the tool needs to write to directly</li></ol>`,53)])])}const k=e(n,[["render",l]]);export{u as __pageData,k as default};
